&lt;div&gt;&amp;nbsp;&lt;/div&gt;

&lt;div&gt;&lt;span style=&quot;&quot;&gt;महिमा और अंशुल के बीच के व्यक्ति = &lt;strong&gt;5&lt;/strong&gt;&lt;/span&gt;&lt;/div&gt;

&lt;div&gt;&amp;nbsp;&lt;/div&gt;

&lt;div&gt;&lt;span style=&quot;&quot;&gt;दी गई जानकारी के अनुसार आरेख होगा,&lt;/span&gt;&lt;/div&gt;

&lt;div&gt;&lt;img alt=&quot;&quot; src=&quot;//storage.googleapis.com/tb-img/production/23/02/F1_Railway_Ishita_22.02.23_D1.png&quot; style=&quot; width: 402px; height: 137px;&quot; /&gt;&lt;/div&gt;

&lt;div&gt;
&lt;div&gt;&lt;span style=&quot;&quot;&gt;पंक्ति में उपस्थित व्यक्तियों&amp;nbsp;की कुल संख्या: 28 + 5 + 22 = &lt;strong&gt;55&lt;/strong&gt;&lt;/span&gt;&lt;/div&gt;

&lt;div&gt;&amp;nbsp;&lt;/div&gt;

&lt;div&gt;&lt;span style=&quot;&quot;&gt;सही उत्तर&amp;nbsp;&amp;#39;55&amp;#39;&lt;/span&gt;&lt;span style=&quot;color: rgb(33, 37, 41);&quot;&gt;&amp;nbsp;है&lt;/span&gt;&lt;span style=&quot;&quot;&gt;।&lt;/span&gt;&lt;/div&gt;
&lt;/div&gt;

